messages.content:
{
  "root_causes": [
    {
      "type": "Configuration - missing BGP process",
      "cause": "No BGP/neighbor configuration exists on R3 (and peers), so a BGP session cannot be established.",
      "evidence": [
        "R3 running-config contains an 'ospf' process (router-id 3.3.3.3) and loopback, but no 'router bgp' or any 'bgp' stanza is present (get_running_config:router3).",
        "R1 and R2 running-configs likewise show OSPF configuration and do not contain any 'router bgp' or 'bgp' configuration (get_running_config:router1, get_running_config:router2).",
        "Topology links show R3 has IP connectivity addresses (10.0.0.9/30 and 10.0.0.6/30) to R1/R2, but absence of BGP config on endpoints explains a BGP session being 'down'."
      ],
      "confidence": 0.95
    }
  ],
  "missing_info": []
}

{
  "intent": "check_and_fix",
  "intent_description": "BGP sessions are down because R3, R1, and R2 lack 'router bgp' configuration; create BGP processes and neighbor adjacencies so sessions come up and routes can be exchanged.",
  "target": "R3",
  "needs_fix": true,
  "plan": {
    "problem": "No BGP process or neighbor configuration on R1, R2, R3; BGP sessions cannot establish between R3 and its peers.",
    "fix_summary": "Create a BGP process (AS 65000) on router1, router2, router3 and configure neighbor relationships between R3<->R1 and R3<->R2 using the directly-connected IPs (assumed peer IPs: R1=10.0.0.8, R3=10.0.0.9; R2=10.0.0.5, R3=10.0.0.6).",
    "plan_steps": [
      {
        "id": 1,
        "device": "router3",
        "action": "create_bgp_process",
        "target": null,
        "parameters": [
          "as 65000",
          "router-id 3.3.3.3"
        ]
      },
      {
        "id": 2,
        "device": "router1",
        "action": "create_bgp_process",
        "target": null,
        "parameters": [
          "as 65000",
          "router-id 1.1.1.1"
        ]
      },
      {
        "id": 3,
        "device": "router2",
        "action": "create_bgp_process",
        "target": null,
        "parameters": [
          "as 65000",
          "router-id 2.2.2.2"
        ]
      },
      {
        "id": 4,
        "device": "router3",
        "action": "add_bgp_neighbor",
        "target": null,
        "parameters": [
          "neighbor 10.0.0.8 remote-as 65000"
        ]
      },
      {
        "id": 5,
        "device": "router3",
        "action": "add_bgp_neighbor",
        "target": null,
        "parameters": [
          "neighbor 10.0.0.5 remote-as 65000"
        ]
      },
      {
        "id": 6,
        "device": "router1",
        "action": "add_bgp_neighbor",
        "target": null,
        "parameters": [
          "neighbor 10.0.0.9 remote-as 65000"
        ]
      },
      {
        "id": 7,
        "device": "router2",
        "action": "add_bgp_neighbor",
        "target": null,
        "parameters": [
          "neighbor 10.0.0.6 remote-as 65000"
        ]
      }
    ]
  }
}

