{
  "intent": "check_and_fix",
  "intent_description": "BGP sessions are down because R3, R1, and R2 lack 'router bgp' configuration; create BGP processes and neighbor adjacencies so sessions come up and routes can be exchanged.",
  "target": "R3",
  "needs_fix": true,
  "plan": {
    "problem": "No 'router bgp' configuration on R1, R2, R3 — BGP sessions are down and routes are not being exchanged.",
    "fix_summary": "Create a BGP process on each router and configure eBGP neighbor relationships on each serial link (R1-R2, R2-R3, R1-R3).",
    "plan_steps": [
      {
        "id": 1,
        "device": "router1",
        "action": "create_bgp_process",
        "target": null,
        "parameters": [
          "as=65001",
          "router_id=1.1.1.1"
        ]
      },
      {
        "id": 2,
        "device": "router2",
        "action": "create_bgp_process",
        "target": null,
        "parameters": [
          "as=65002",
          "router_id=2.2.2.2"
        ]
      },
      {
        "id": 3,
        "device": "router3",
        "action": "create_bgp_process",
        "target": null,
        "parameters": [
          "as=65003",
          "router_id=3.3.3.3"
