      },
      {
        "id": 4,
        "device": "router1",
        "action": "add_bgp_neighbor",
        "target": "10.0.0.2",
        "parameters": [
          "remote_as=65002"
        ]
      },
      {
        "id": 5,
        "device": "router1",
        "action": "add_bgp_neighbor",
        "target": "10.0.0.9",
